const CSVReader=require("./utils/csvReader"),NFTTracker=require("./services/nftTracker"),config=require("./config");let nftTracker=null;async function main(){try{console.log("🚀 Starting NFT Tracker Bot..."),console.log("=".repeat(50));const csvReader=new CSVReader(config.csvFile),wallets=await csvReader.readWallets();0===wallets.length&&(console.error("❌ No wallets found in CSV file!"),process.exit(1)),nftTracker=new NFTTracker,await nftTracker.initialize(wallets),console.log("\n✅ Bot initialized successfully!"),console.log(`📊 Tracking ${wallets.length} wallets`),console.log(`⏱️  Scan interval: ${config.scanInterval/1e3/60} minutes`),console.log("🔗 Chains: OpenSea-supported EVM chains"),console.log("=".repeat(50)),await nftTracker.startTracking()}catch(error){console.error("❌ Error starting bot:",error),process.exit(1)}}process.on("SIGINT",(async()=>{console.log("\n🛑 Shutting down NFT Tracker Bot..."),nftTracker&&nftTracker.discordNotifier&&await nftTracker.discordNotifier.disconnect(),process.exit(0)})),process.on("SIGTERM",(async()=>{console.log("\n🛑 Shutting down NFT Tracker Bot..."),nftTracker&&nftTracker.discordNotifier&&await nftTracker.discordNotifier.disconnect(),process.exit(0)})),main();